41	/**
42	 * 寫入一筆 event
43	 */
44	export function logEvent(
45	  type: EventType,
46	  payload: Record<string, unknown> = {},
47	  opts: { chatId?: number; userId?: number } = {}
48	): void {
49	  const event: StateEvent = {
50	    ts: new Date().toISOString(),
51	    type,
52	    ...opts,
53	    payload,
54	  };
55	
56	  try {
57	    // 確保目錄存在
58	    const dir = dirname(EVENT_LOG_PATH);
59	    if (!existsSync(dir)) {
60	      mkdirSync(dir, { recursive: true });
61	    }
62	
63	    appendFileSync(EVENT_LOG_PATH, JSON.stringify(event) + "\n", "utf-8");
64	  } catch (err) {
65	    // Event log 失敗不應該影響主流程
66	    console.error("[event-log] Failed to write event:", err);
67	  }
68	}
