70	/**
71	 * 讀取最近 n 筆 events
72	 */
73	export function getRecentEvents(n: number = 50): StateEvent[] {
74	  if (!existsSync(EVENT_LOG_PATH)) return [];
75	
76	  try {
77	    const content = readFileSync(EVENT_LOG_PATH, "utf-8");
78	    const lines = content.trim().split("\n").filter(Boolean);
79	    const events = lines
80	      .slice(-n)
81	      .map((line) => {
82	        try {
83	          return JSON.parse(line) as StateEvent;
84	        } catch {
85	          return null;
86	        }
87	      })
88	      .filter((e): e is StateEvent => e !== null);
89	
90	    return events;
91	  } catch {
