110	/**
111	 * 滾動清理：刪除超過 RETENTION_DAYS 的 events
112	 * 
113	 * 建議在 /dream 時呼叫
114	 */
115	export function rotateEventLog(): { deleted: number; kept: number } {
116	  if (!existsSync(EVENT_LOG_PATH)) {
117	    return { deleted: 0, kept: 0 };
118	  }
119	
120	  try {
121	    const content = readFileSync(EVENT_LOG_PATH, "utf-8");
122	    const lines = content.trim().split("\n").filter(Boolean);
123	
124	    const cutoff = new Date();
125	    cutoff.setDate(cutoff.getDate() - RETENTION_DAYS);
126	    const cutoffStr = cutoff.toISOString();
127	
128	    const kept: string[] = [];
129	    let deleted = 0;
130	
131	    for (const line of lines) {
132	      try {
133	        const event = JSON.parse(line) as StateEvent;
134	        if (event.ts >= cutoffStr) {
135	          kept.push(line);
136	        } else {
137	          deleted++;
138	        }
139	      } catch {
140	        // 無法解析的行直接丟棄
141	        deleted++;
142	      }
143	    }
144	
145	    writeFileSync(EVENT_LOG_PATH, kept.join("\n") + (kept.length ? "\n" : ""), "utf-8");
146	
147	    return { deleted, kept: kept.length };
148	  } catch (err) {
149	    console.error("[event-log] Failed to rotate:", err);
150	    return { deleted: 0, kept: 0 };
151	  }
152	}
