154	/**
155	 * 統計過去 days 天的 tool_call 使用次數，依工具名稱聚合。
156	 *
157	 * 回傳依使用次數由多到少排序的陣列；total 為總呼叫數、failed 為失敗數。
158	 */
159	export function getToolUsageStats(days: number = 7): {
160	  byTool: Array<{ name: string; total: number; failed: number }>;
161	  total: number;
162	  failed: number;
163	} {
164	  const cutoff = new Date();
165	  cutoff.setDate(cutoff.getDate() - days);
166	  const cutoffStr = cutoff.toISOString();
167	
168	  const counts = new Map<string, { total: number; failed: number }>();
169	  let total = 0;
170	  let failed = 0;
171	
172	  for (const e of getRecentEvents(10000)) {
173	    if (e.type !== "tool_call" || e.ts < cutoffStr) continue;
174	    const name = (e.payload?.name as string) ?? "tool";
175	    const isFail = e.payload?.status === "failed";
176	    const cur = counts.get(name) ?? { total: 0, failed: 0 };
177	    cur.total++;
178	    if (isFail) cur.failed++;
179	    counts.set(name, cur);
180	    total++;
181	    if (isFail) failed++;
182	  }
183	
184	  const byTool = [...counts.entries()]
185	    .map(([name, v]) => ({ name, total: v.total, failed: v.failed }))
186	    .sort((a, b) => b.total - a.total);
187	
188	  return { byTool, total, failed };
189	}
