192	 * 取得 event log 統計
193	 */
194	export function getEventLogStats(): {
195	  totalEvents: number;
196	  oldestEvent?: string;
197	  newestEvent?: string;
198	  byType: Record<string, number>;
199	} {
200	  const events = getRecentEvents(10000); // 讀取全部（最多 10000）
201	
202	  if (events.length === 0) {
203	    return { totalEvents: 0, byType: {} };
204	  }
205	
206	  const byType: Record<string, number> = {};
207	  for (const e of events) {
208	    byType[e.type] = (byType[e.type] || 0) + 1;
209	  }
210	
211	  return {
212	    totalEvents: events.length,
213	    oldestEvent: events[0]?.ts,
214	    newestEvent: events[events.length - 1]?.ts,
215	    byType,
216	  };
217	}
