17	const DAYS_WINDOW = 7;
18	const MIN_SESSIONS = 3;    // must appear in ≥3 different sessions
19	const STOP_WORDS = new Set([
20	  "的", "了", "是", "在", "我", "有", "和", "就", "不", "人", "都", "一", "這",
21	  "那", "要", "會", "對", "也", "說", "到", "可以", "沒有", "什麼", "怎麼",
22	  "the", "a", "an", "is", "are", "was", "were", "be", "been", "being",
23	  "have", "has", "had", "do", "does", "did", "will", "would", "could",
24	  "should", "may", "might", "shall", "can", "need", "dare", "ought",
25	  "to", "of", "in", "for", "on", "with", "at", "by", "from", "as",
26	  "into", "through", "during", "before", "after", "above", "below",
27	  "it", "this", "that", "these", "those", "i", "you", "he", "she",
28	  "we", "they", "me", "him", "her", "us", "them", "my", "your",
29	  "his", "its", "our", "their", "and", "but", "or", "not", "no",
30	  "好", "嗯", "ok", "yes", "no", "push", "繼續", "done",
31	]);
