33	/** Extract user messages from a session markdown file. */
34	function extractUserMessages(content: string): string[] {
35	  const msgs: string[] = [];
36	  const blocks = content.split(/^### 👤 User/m);
37	  for (let i = 1; i < blocks.length; i++) {
38	    // Take text until next ### header
39	    const end = blocks[i].indexOf("\n### ");
40	    const raw = end > 0 ? blocks[i].slice(0, end) : blocks[i];
41	    // Strip metadata lines (Intent hint, Skill routing, timestamps, relay captions)
42	    const lines = raw.split("\n").filter(l =>
43	      !l.startsWith("[") && !l.startsWith("---") && !l.startsWith("### ") &&
44	      !/^\s*\(.*[上下]午\d/.test(l) &&
45	      !/^\s*這是委派/.test(l) &&
46	      l.trim().length > 2
47	    );
48	    const msg = lines.join(" ").trim();
49	    if (msg.length > 5 && msg.length < 200) msgs.push(msg);
50	  }
51	  return msgs;
52	}
53	
54	/** Tokenize a message into meaningful bigrams. */
55	function extractBigrams(msg: string): string[] {
56	  const words = msg.toLowerCase()
57	    .replace(/[^\w\u4e00-\u9fff\s]/g, " ")
58	    .split(/\s+/)
59	    .filter(w => w.length > 1 && !STOP_WORDS.has(w));
60	  const bigrams: string[] = [];
61	  for (let i = 0; i < words.length - 1; i++) {
62	    bigrams.push(`${words[i]} ${words[i + 1]}`);
63	  }
64	  // Also include single meaningful words ≥3 chars
65	  for (const w of words) {
66	    if (w.length >= 3) bigrams.push(w);
67	  }
68	  return bigrams;
69	}
