71	/** Load existing skill keywords for comparison. */
72	function loadSkillKeywords(): Set<string> {
73	  const skillDir = detectSkillDir();
74	  const keywords = new Set<string>();
75	  if (!existsSync(skillDir)) return keywords;
76	  for (const entry of readdirSync(skillDir, { withFileTypes: true })) {
77	    if (!entry.isDirectory()) continue;
78	    // Add the skill folder name as a keyword
79	    keywords.add(entry.name.replace(/^ms-/, "").replace(/-/g, " "));
80	    // Read SKILL.md description for additional keywords
81	    const skillFile = path.join(skillDir, entry.name, "SKILL.md");
82	    if (!existsSync(skillFile)) continue;
83	    const content = readFileSync(skillFile, "utf8").slice(0, 500);
84	    const descMatch = content.match(/description:\s*(.+)/);
85	    if (descMatch) {
86	      const desc = descMatch[1].toLowerCase();
87	      // Extract Chinese/English words from description
88	      const descWords = desc.replace(/[^\w\u4e00-\u9fff\s]/g, " ").split(/\s+/)
89	        .filter(w => w.length >= 3);
90	      for (const w of descWords) keywords.add(w);
91	    }
92	  }
93	  return keywords;
94	}
