96	/**
97	 * Scan recent sessions and produce skill candidates.
98	 * Returns patterns that appear in ≥3 sessions with no matching skill.
99	 */
100	export function suggestSkills(): SkillCandidate[] {
101	  const sessDir = path.join(config.memoryDir, "sessions");
102	  if (!existsSync(sessDir)) return [];
103	
104	  const cutoff = Date.now() - DAYS_WINDOW * 86400_000;
105	  const files = readdirSync(sessDir)
106	    .filter(f => f.startsWith("session-") && f.endsWith(".md"))
107	    .filter(f => {
108	      const full = path.join(sessDir, f);
109	      try {
110	        return statSync(full).mtimeMs >= cutoff;
111	      } catch { return false; }
112	    });
113	
114	  // Count bigrams across sessions (deduplicated per session)
115	  const bigramSessions = new Map<string, Set<string>>(); // bigram → set of session filenames
116	  const bigramExamples = new Map<string, string[]>();     // bigram → example messages
117	
118	  for (const file of files) {
119	    const content = readFileSync(path.join(sessDir, file), "utf8");
120	    const msgs = extractUserMessages(content);
121	    const sessionBigrams = new Set<string>();
122	    for (const msg of msgs) {
123	      for (const bg of extractBigrams(msg)) {
124	        if (!sessionBigrams.has(bg)) {
125	          sessionBigrams.add(bg);
126	          if (!bigramSessions.has(bg)) bigramSessions.set(bg, new Set());
127	          bigramSessions.get(bg)!.add(file);
128	          if (!bigramExamples.has(bg)) bigramExamples.set(bg, []);
129	          const ex = bigramExamples.get(bg)!;
130	          if (ex.length < 3) ex.push(msg.slice(0, 100));
131	        }
132	      }
133	    }
134	  }
135	
136	  // Filter: ≥MIN_SESSIONS occurrences
137	  const skillKeywords = loadSkillKeywords();
138	  const candidates: SkillCandidate[] = [];
139	
140	  for (const [bigram, sessions] of bigramSessions) {
141	    if (sessions.size < MIN_SESSIONS) continue;
142	    // Skip if matches an existing skill keyword
143	    if (skillKeywords.has(bigram)) continue;
144	    // Skip if any word in the bigram is a skill keyword
145	    const words = bigram.split(" ");
146	    if (words.some(w => skillKeywords.has(w))) continue;
147	
148	    candidates.push({
149	      pattern: bigram,
150	      count: sessions.size,
151	      examples: bigramExamples.get(bigram) ?? [],
152	    });
153	  }
154	
155	  // Sort by frequency descending, take top 10
156	  candidates.sort((a, b) => b.count - a.count);
157	  return candidates.slice(0, 10);
158	}
